const redditRaw = $('Fetch Reddit Trends').first().json;
const posts = redditRaw?.data?.children || [];
const trendLines = posts.slice(0, 8).map(p => p?.data?.title || '').filter(t => t.length > 5);
const trendContext = trendLines.join('\n• ') || 'No specific trends today';

const today = new Date().toISOString().split('T')[0];

const allRows = $input.all();
const pending = allRows.filter(row => {
  const s = row.json;
  const statusOk = !s.status || s.status.toLowerCase() === 'pending';
  const dateOk = !s.scheduled_date || s.scheduled_date <= today;
  const hasContent = s.topic && s.brand && s.platform;
  return statusOk && dateOk && hasContent;
});

if (pending.length === 0) {
  return [{ json: { _empty: true, trend_context: trendContext } }];
}

return pending.map(row => ({
  json: {
    ...row.json,
    _row_number: row.json._rowNumber || row.json.row_number,
    trend_context: trendContext
  }
}));

const row = $input.first().json;
const brand = (row.brand || 'floatup').toLowerCase().trim();
const platform = (row.platform || 'instagram').toLowerCase().trim();
const contentType = (row.content_type || 'educational').toLowerCase().trim();

const BRANDS = {
  floatup: {
    name: 'Floatup',
    desc: 'task management, CA compliance, and client operations SaaS for professional teams in India',
    tone: 'professional, confident, ROI-focused, direct — like a trusted advisor not a salesman',
    audience: 'Chartered Accountants, startup founders, project managers, growing professional firms',
    cta: 'floatup.app',
    colors: 'dark navy #1A1A2E and orange #FF6B35',
    ig_hashtags: '#TaskManagement #CACompliance #StartupIndia #Floatup #CAsOfInstagram #FinanceTools #ProductivityHacks',
    li_hashtags: '#CharteredAccountant #TaskManagement #StartupIndia #Floatup #CApractice'
  },
  ai_community: {
    name: 'AI Community',
    desc: 'a community and resource hub for developers and solopreneurs building with AI tools',
    tone: 'casual, educational, insider-knowledge, slightly irreverent — like a smart friend who gets it',
    audience: 'developers, solopreneurs, AI enthusiasts, indie hackers, tech founders',
    cta: 'link in bio',
    colors: 'dark theme with purple and blue accents',
    ig_hashtags: '#AITools #BuildWithAI #Solopreneur #IndieHackers #AICommunity #TechIndia #NoCode #AIAutomation',
    li_hashtags: '#ArtificialIntelligence #AITools #Solopreneur #IndieHackers #BuildWithAI'
  }
};

const cfg = BRANDS[brand] || BRANDS.floatup;
const topic = row.topic || 'productivity';
const keyMsg = row.key_message || '';
const targetEmotion = row.target_emotion || 'curiosity';
const trends = row.trend_context || 'no specific trends today';
const designPrompt = row.claude_design_prompt || '';

let prompt = '';
const isDesign = platform === 'instagram' && contentType === 'custom_design' && designPrompt.length > 5;

if (isDesign) {
  prompt = `You are an expert UI/visual designer specialising in Instagram content cards.\n\nGenerate a complete self-contained HTML+CSS card exactly 1080x1080 pixels for an Instagram post.\n\nDESIGN BRIEF:\n${designPrompt}\n\nBRAND: ${cfg.name}\nBRAND COLORS: ${cfg.colors}\nBRAND TAG: ${cfg.cta}\nAUDIENCE: ${cfg.audience}\n\nTECHNICAL REQUIREMENTS:\n- Outer div must be exactly width:1080px height:1080px\n- All CSS inline or in a <style> tag — NO external stylesheets or images\n- Google Fonts via @import is allowed\n- Bold typography, strong contrast, clear visual hierarchy\n- Brand watermark small at bottom-right: ${cfg.cta}\n- Must look stunning and professional\n\nOutput ONLY valid HTML. Start directly with <!DOCTYPE html> or <div>. No explanation, no markdown.`;

} else if (platform === 'instagram' && contentType === 'meme') {
  prompt = `You are a viral meme creator for B2B SaaS brands. Think HireZapp Instagram style — bold, funny, relatable.\n\nBRAND: ${cfg.name} — ${cfg.desc}\nAUDIENCE: ${cfg.audience}\nTOPIC/THEME: ${topic}\nCORE MESSAGE: ${keyMsg}\n\nCreate a relatable, funny meme post. Think: stressed animal at laptop, before/after format, POV format, chaos scenario — the kind that makes a CA stop scrolling and say \'same\'.\n\nThe meme should make the audience laugh AND subtly show how ${cfg.name} solves their pain. Never be corporate.\n\nOutput ONLY this JSON (no markdown):\n{\n  \

}`;

} else if (platform === 'instagram') {
  prompt = `You are a top Instagram content strategist for B2B SaaS and creator brands.

BRAND: ${cfg.name}
DESCRIPTION: ${cfg.desc}
TONE: ${cfg.tone}
AUDIENCE: ${cfg.audience}

TODAY'S TRENDING TOPICS (use for relevance — DO NOT copy directly):
• ${trends}

CONTENT BRIEF:
- Content Type: ${contentType}
- Topic: ${topic}
- Core Message: ${keyMsg}
- Target Emotion: ${targetEmotion}

INSTAGRAM RULES:
- Caption max 220 chars (not including hashtags)
- Hook must work in first 2 lines before the more button — impossible to skip
- Hashtags at the very end after 2-3 line breaks
- Never start with the brand name. Feel native, NOT like an ad

Output ONLY this JSON (no markdown):
{
  \

}`;

} else {
  prompt = `You are an expert LinkedIn content strategist for B2B founders and practitioners.

YOU ARE WRITING AS: A practicing Chartered Accountant who co-founded ${cfg.name}
BRAND: ${cfg.name} — ${cfg.desc}
TONE: ${cfg.tone} — written as a real founder, NOT a marketer
AUDIENCE: ${cfg.audience}

TODAY'S TRENDING TOPICS:
• ${trends}

CONTENT BRIEF:
- Content Type: ${contentType}
- Topic: ${topic}
- Core Message: ${keyMsg}
- Target Emotion: ${targetEmotion}

LINKEDIN RULES:
- First 2 lines MUST work standalone as hook (shown before see more)
- Text posts get MORE reach — this is text only, no image
- NO external links in post body — link goes in first comment
- Max 3-5 hashtags at the very end
- End with a genuine question to drive comments
- 150-350 words optimal
- Write like a human with a strong opinion, not a company announcement

Output ONLY this JSON (no markdown):
{
  \

\n}`;
}

return [{ json: { ...row, brand_cfg: cfg, gemini_prompt: prompt, platform, brand, content_type: contentType, is_design: isDesign } }];

const raw = $input.first().json;
const text = raw?.candidates?.[0]?.content?.parts?.[0]?.text || '';
const ctx = $('Build Platform Prompt').first().json;
const platform = ctx.platform;
const contentType = ctx.content_type || '';
const isDesign = ctx.is_design || false;

let result = { ...ctx };

if (isDesign) {
  // Response is raw HTML — strip markdown code fences if present
  const html = text.replace(/```html\s*/gi, '').replace(/```\s*/g, '').trim();
  result.design_html = html;
  result.full_post = '';
  result.hook = '';
  result.predicted_score = 8;
  result.is_meme = false;
  result.image_search_query = '';
  result.top_label = '';
  result.image_headline = ctx.topic || '';
  result.image_subtext = '';
  result.image_headline = '';
  return [{ json: result }];
}

const cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
let parsed = {};
try { parsed = JSON.parse(cleaned); }
catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) { try { parsed = JSON.parse(match[0]); } catch(e2) {} }
}

result.predicted_score = Number(parsed.predicted_score) || 5;

if (platform === 'instagram') {
  result.hook               = parsed.hook || '';
  result.caption_body       = parsed.caption || '';
  result.hashtags           = parsed.hashtags || ctx.brand_cfg?.ig_hashtags || '';
  result.top_label          = parsed.top_label || '';
  result.image_headline     = parsed.image_headline || (ctx.topic || '').toUpperCase();
  result.image_subtext      = parsed.image_subtext || '';
  result.image_search_query = parsed.image_search_query || '';
  result.cta                = parsed.cta || 'floatup.app';
  result.is_meme            = contentType === 'meme';
  result.full_post          = `${parsed.hook}\n\n${parsed.caption || ''}\n\n${parsed.hashtags}`.trim();
result.claude_design_prompt = parsed.claude_design_prompt || '';
} else {
  result.hook          = parsed.hook || '';
  result.full_post     = parsed.full_post || '';
  result.hashtags      = parsed.hashtags || ctx.brand_cfg?.li_hashtags || '';
  result.first_comment = parsed.first_comment || '';
  result.claude_design_prompt = parsed.claude_design_prompt || '';
  result.image_headline = '';
  result.image_subtext  = '';
  result.is_meme        = false;
  result.image_search_query = '';
  result.cta            = ctx.brand_cfg?.cta || '';
}

return [{ json: result }];

